        </section>

        <form className={styles.form} onSubmit={handleSubmit}>
          <label className={styles.label}>
            Select an image
            <input
              name="file"
              type="file"
              accept="image/*"
              required
              className={styles.input}
            />
          </label>
          <button
            type="submit"
            className={styles.button}
            disabled={uploadFile.isPending}
